    var _buf: std.ArrayList(u8) = .empty;
    while (true) {
        var _b: [1]u8 = undefined;
        const _n = std.posix.recv(conn.stream.handle, &_b, 0) catch break;
        if (_n == 0) break;
        if (_b[0] == '\n') break;
        if (_b[0] != '\r') _buf.append(std.heap.page_allocator, _b[0]) catch break;
    }
